import{_ as t,o as n,c as i,a3 as r}from"./chunks/framework.CjquFG0V.js";const l=JSON.parse('{"title":"17. Gender Based Discrimination","description":"","frontmatter":{"title":"17. Gender Based Discrimination","eba":"Mental Health Services 2024-2028","topics":["preliminary","discrimination"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/preliminary/17-gender-based-discrimination.md","filePath":"ebas/mental-health/common-terms/preliminary/17-gender-based-discrimination.md"}'),a={name:"ebas/mental-health/common-terms/preliminary/17-gender-based-discrimination.md"};function s(o,e,d,m,p,g){return n(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="_17-gender-based-discrimination" tabindex="-1">17. Gender Based Discrimination <a class="header-anchor" href="#_17-gender-based-discrimination" aria-label="Permalink to &quot;17. Gender Based Discrimination&quot;">​</a></h1><p><strong>17.1</strong> The parties agree, in conjunction with the Department, to maintain a Gender- Based Standing Committee (GBSC) during this Agreement.</p><p><strong>17.2</strong> The purpose of the GBSC will be to:</p><p><strong>(a)</strong> review audit results</p><p><strong>(b)</strong> promote gender equity initiatives</p><p><strong>(c)</strong> identify and address any gender pay gaps in the public sector organisation; and</p><p><strong>(d)</strong> promote job security.</p><p><strong>17.3</strong> The GBSC will schedule a minimum of four meetings per year.</p><p><strong>17.4</strong> The GBSC will be comprised of:</p><p><strong>(i)</strong> representative Employers through their CEOs or their nominees</p><p><strong>(ii)</strong> the Unions; and</p><p><strong>(iii)</strong> the VHIA.</p><p><strong>(iv)</strong> The GBSC may, by unanimous agreement of its sitting members, also include other health sector unions who are not covered by this Agreement to meet the objectives at clause 17.</p><p><strong>17.5</strong> The Employers’ gender equity activities, including Audit and Action Plan will be a standing agenda item at WIC meetings.</p><p>Plain language terms: gender discrimination, sex discrimination, pay equity.</p>',15)])])}const h=t(a,[["render",s]]);export{l as __pageData,h as default};
